-- sqlcl_snapshot src/database/myapp/tables/expenses.sql:null:490563435283af8f158cd2c19984bb33bc686dec:create

create table expenses (
    expense_id    number generated by default as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache 20 noorder
    nocycle nokeep noscale not null enable,
    team_id       number not null enable,
    expense_date  date not null enable,
    category      varchar2(40 byte) not null enable,
    description   varchar2(240 byte),
    amount        number(12, 2) not null enable,
    vendor_name   varchar2(120 byte),
    approved_flag char(1 byte) default 'N' not null enable
);

alter table expenses
    add constraint expenses_amount_ck check ( amount >= 0 ) enable;

alter table expenses
    add constraint expenses_approved_ck
        check ( approved_flag in ( 'Y', 'N' ) ) enable;

alter table expenses
    add constraint expenses_category_ck
        check ( category in ( 'TRAVEL', 'EQUIPMENT', 'PAYROLL', 'MEDICAL', 'FACILITY',
                              'MARKETING', 'OTHER' ) ) enable;

alter table expenses
    add constraint expenses_pk primary key ( expense_id )
        using index enable;

